class Solution {
    public int numberOfSpecialChars(String word) {
        int count = 0;
        for (int i = 0; i < word.length(); i++) {
            char lower = Character.toLowerCase(word.charAt(i));
            char upper = Character.toUpperCase(word.charAt(i));
            if (lower == upper) {
                count++;
            }
        }
        return count;
    }
}
